  1	import {
  2	  Chart,
  3	  ChartAxis,
  4	  ChartBar,
  5	  ChartLegendTooltip,
  6	  ChartLegendTooltipProps,
  7	  ChartStack,
  8	  createContainer,
  9	} from '@patternfly/react-charts';
 10	import { getResizeObserver } from '@patternfly/react-core';
 11	import { Alert, Card, CardBody } from '@patternfly/react-core';
 12	import React from 'react';
 13	import { useTranslation } from 'react-i18next';
 14	import { dateToFormat, getTimeFormatFromInterval, getTimeFormatFromTimeRange } from '../date-utils';
 15	import {
 16	  isMatrixResult,
 17	  MetricValue,
 18	  QueryRangeResponse,
 19	  Schema,
 20	  TimeRange,
 21	  TimeRangeNumber,
 22	} from '../logs.types';
 23	import { getSeverityColor, Severity, severityAbbreviations, severityFromString } from '../severity';
 24	import { TestIds } from '../test-ids';
 25	import { intervalFromTimeRange, numericTimeRange } from '../time-range';
 26	import { valueWithScalePrefix } from '../value-utils';
 27	import { CenteredContainer } from './centered-container';
 28	import './logs-histogram.css';
 29	
 30	const GRAPH_HEIGHT = 130;
 31	const LEFT_PADDING = 50;
 32	const BOTTOM_PADDING = 50;
 33	const TOP_PADDING = 10;
 34	
 35	const SORTED_CHART_GROUPS: Array<Severity> = [
 36	  'critical',
 37	  'error',
 38	  'warning',
 39	  'debug',
 40	  'info',
 41	  'trace',
 42	  'unknown',
 43	];
 44	
 45	type ChartData = {
 46	  x: number;
 47	  y: number;
 48	  name: string;
 49	  time: string;
 50	  label: string;
 51	};
 52	
 53	type HistogramChartData = Record<Severity, Array<ChartData>>;
 54	type HistogramData = Record<Severity, Array<MetricValue>>;
 55	
 56	interface LogHistogramProps {
 57	  histogramData?: QueryRangeResponse;
 58	  timeRange?: TimeRange;
 59	  onChangeTimeRange?: (timeRange: TimeRange) => void;
 60	  interval?: number;
 61	  isLoading?: boolean;
 62	  error?: unknown;
 63	  schema?: Schema;
 64	  timezone?: string;
 65	}
 66	
 67	const resultHasAbreviation = (
 68	  result: Record<string, string>,
 69	  abbreviation: Array<string>,
 70	  schema: Schema | undefined,
 71	): boolean => {
 72	  if (schema == Schema.otel) {
 73	    return !!result.severity_text && abbreviation.includes(result.severity_text);
 74	  }
 75	  return !!result.level && abbreviation.includes(result.level);
 76	};
 77	
 78	const aggregateMetricsLogData = (response?: QueryRangeResponse, schema?: Schema): HistogramData => {
 79	  const histogramData: HistogramData = {
 80	    critical: [],
 81	    error: [],
 82	    warning: [],
 83	    info: [],
 84	    debug: [],
 85	    trace: [],
 86	    unknown: [],
 87	    other: [],
 88	  };
 89	
 90	  const data = response?.data;
 91	
 92	  if (isMatrixResult(data)) {
 93	    for (const logData of data.result) {
 94	      let logDataIngroup = false;
 95	      for (const [group, abbreviations] of Object.entries(severityAbbreviations)) {
 96	        if (resultHasAbreviation(logData.metric, abbreviations, schema)) {
 97	          histogramData[group as Severity].push(...logData.values);
 98	          logDataIngroup = true;
 99	          break;
100	        }
101	      }
102	
103	      if (!logDataIngroup) {
104	        histogramData.unknown.push(...logData.values);
105	      }
106	    }
107	  }
108	
109	  return histogramData;
110	};
111	
112	const metricValueToChartData = (
113	  group: Severity,
114	  value: Array<MetricValue>,
115	  interval: number,
116	  timezone?: string,
117	): Array<ChartData> => {
118	  const timeEntries = new Set<number>();
119	  const chartData: Array<ChartData> = [];
120	
121	  for (const metric of value) {
122	    const time = parseFloat(String(metric[0])) * 1000;
123	    const formattedTime = dateToFormat(time, getTimeFormatFromInterval(interval), timezone);
124	
125	    // Prevent duplicate entries to avoid chart rendering issues
126	    if (!timeEntries.has(time)) {
127	      timeEntries.add(time);
128	      chartData.push({
129	        x: time,
130	        y: parseInt(String(metric[1]), 10),
131	        name: group,
132	        time: formattedTime,
133	        label: `${formattedTime} ${group}: ${metric[1]}`,
134	      });
135	    }
136	  }
137	
138	  return chartData;
139	};
140	
141	const getChartsData = (
142	  data: HistogramData,
143	  interval: number,
144	  timezone?: string,
145	): HistogramChartData => {
146	  const chartsData: HistogramChartData = {} as HistogramChartData;
147	
148	  Object.keys(data).forEach((group) => {
149	    const severityGroup = severityFromString(group) ?? 'other';
150	    const chartData = metricValueToChartData(
151	      severityGroup,
152	      data[severityGroup],
153	      interval,
154	      timezone,
155	    );
156	
157	    chartsData[severityGroup] = chartData;
158	  });
159	
160	  return chartsData;
161	};
162	
163	const tickCountFromTimeRange = (timeRange: TimeRangeNumber, interval: number): number =>
164	  Math.ceil((timeRange.end - timeRange.start) / interval);
165	
166	const HistogramTooltip: React.FC<
167	  ChartLegendTooltipProps & { interval: number; timezone?: string }
168	> = ({ interval, timezone, ...props }) => {
169	  const { x: xProps, y: yProps, center, height } = props;
170	
171	  if (!center) {
172	    return null;
173	  }
174	
175	  const { x, y } = center;
176	
177	  const xCoord = x ?? xProps;
178	  const yCoord = y ?? yProps;
179	
180	  if (xCoord === undefined || yCoord === undefined || height === undefined) {
181	    return null;
182	  }
183	
184	  const fixedProps = {
185	    ...props,
186	    center: { x: xCoord, y: yCoord, ...props.center },
187	  };
188	
189	  return (
190	    <>
191	      <ChartLegendTooltip
192	        {...fixedProps}
193	        title={(datum) => dateToFormat(datum.x ?? 0, getTimeFormatFromInterval(interval), timezone)}
194	        constrainToVisibleArea
195	      />
196	      <line
197	        className="lv-plugin__histogram__tooltip-line"
198	        x1={xCoord}
199	        x2={xCoord}
200	        y1={TOP_PADDING}
201	        y2={height - BOTTOM_PADDING}
202	      />
203	    </>
204	  );
205	};
206	
207	interface SelectionComponentProps {
208	  x?: number;
209	  y?: number;
210	  width?: number;
211	  height?: number;
212	}
213	
214	const BrushHandleComponent: React.FC<SelectionComponentProps> = ({ x, y, width, height }) => {
215	  if (x === undefined || y === undefined || width === undefined || height === undefined) {
216	    return null;
217	  }
218	
219	  const triangleSize = 6;
220	
221	  return (
222	    <g>
223	      <line
224	        x1={x}
225	        x2={x}
226	        y1={y}
227	        y2={height + y}
228	        style={{ stroke: 'var(--pf-v6-chart-color-blue-300)', strokeDasharray: '5 3' }}
229	      />
230	      <polygon
231	        points={`${x},${y} ${x - triangleSize},${y - triangleSize} ${x + triangleSize},${
232	          y - triangleSize
233	        }`}
234	        style={{ fill: 'var(--pf-v6-chart-color-blue-300)' }}
235	      />
236	    </g>
237	  );
238	};
239	
240	const clampTimeToChartRange = (time: number, timeRange: TimeRangeNumber): number => {
241	  if (time > timeRange.end) {
242	    return timeRange.end;
243	  }
244	
245	  if (time < timeRange.start) {
246	    return timeRange.start;
247	  }
248	
249	  return time;
250	};
251	
252	const SelectVoronoiContainer = createContainer('brush', 'voronoi');
253	
254	export const LogsHistogram: React.FC<LogHistogramProps> = ({
255	  histogramData,
256	  timeRange,
257	  isLoading,
258	  error,
259	  onChangeTimeRange,
260	  interval,
261	  schema,
262	  timezone,
263	}) => {
264	  const { t } = useTranslation('plugin__logging-view-plugin');
265	
266	  const containerRef = React.useRef<HTMLDivElement | null>(null);
267	  const [width, setWidth] = React.useState<number>(0);
268	  const [timeRangeValue, setTimeRangeValue] = React.useState(numericTimeRange(timeRange));
269	
270	  const handleResize = () => {
271	    if (containerRef.current?.clientWidth) {
272	      setWidth(containerRef.current.clientWidth);
273	    }
274	  };
275	
276	  React.useEffect(() => {
277	    const observer = containerRef.current
278	      ? getResizeObserver(containerRef.current, handleResize)
279	      : undefined;
280	    return () => observer?.();
281	  }, []);
282	
283	  React.useEffect(() => {
284	    setTimeRangeValue(numericTimeRange(timeRange));
285	  }, [timeRange, interval, histogramData]);
286	
287	  const intervalValue = interval ?? intervalFromTimeRange(timeRangeValue);
288	
289	  const groupsCharts = React.useMemo(() => {
290	    if (!histogramData || histogramData.data.result.length === 0) {
291	      return { ticks: [], charts: null, availableGroups: [] };
292	    }
293	
294	    const data = aggregateMetricsLogData(histogramData, schema);
295	    const chartsData = getChartsData(data, intervalValue, timezone);
296	
297	    const tickCount = tickCountFromTimeRange(timeRangeValue, intervalValue);
298	
299	    const availableGroups = SORTED_CHART_GROUPS.filter(
300	      (group: Severity) => chartsData && chartsData[group] && chartsData[group].length > 0,
301	    );
302	
303	    const maxBarWidth = width / 10;
304	
305	    const charts = availableGroups.map((group: Severity, index: number) => {
306	      let barData = chartsData[group];
307	
308	      /**
309	       * If we are in subsecond resolution, clamp time to current range so the bar is visible
310	       *  */
311	      if (timeRangeValue.end - timeRangeValue.start <= 1000) {
312	        barData = barData.map((d) => ({ ...d, x: clampTimeToChartRange(d.x, timeRangeValue) }));
313	      }
314	
315	      return (
316	        <ChartBar
317	          key={`${group}-${index}`}
318	          data={barData}
319	          name={group}
320	          barWidth={Math.min(maxBarWidth, (width / tickCount) * 0.8)}
321	          style={{ data: { fill: getSeverityColor(group) } }}
322	          labelComponent={<g />}
323	        />
324	      );
325	    });
326	
327	    return {
328	      charts,
329	      availableGroups,
330	    };
331	  }, [histogramData, timeRangeValue, interval, width]);
332	
333	  const legendData = React.useMemo(
334	    () =>
335	      groupsCharts.availableGroups.map((group) => ({
336	        name: group,
337	        childName: group,
338	        symbol: { fill: getSeverityColor(group) },
339	      })),
340	    [groupsCharts.availableGroups],
341	  );
342	
343	  const dataIsEmpty = histogramData?.data.result.length === 0;
344	
345	  const handleTimeRangeSelection = (domain?: { x?: Array<Date | number> }) => {
346	    if (
347	      domain?.x &&
348	      domain.x.length > 1 &&
349	      typeof domain.x[0] === 'object' &&
350	      typeof domain.x[1] === 'object'
351	    ) {
352	      const start = domain.x[0];
353	      const end = domain.x[1];
354	
355	      if (start.getTime() < end.getTime()) {
356	        onChangeTimeRange?.({ start: start.getTime(), end: end.getTime() });
357	      }
358	    }
359	  };
360	
361	  return (
362	    <Card data-test={TestIds.LogsHistogram}>
363	      <CardBody>
364	        <div ref={containerRef} style={{ height: GRAPH_HEIGHT }}>
365	          {error ? (
366	            <CenteredContainer>
367	              <Alert
368	                variant="danger"
369	                isInline
370	                isPlain
371	                title={(error as Error).message || String(error)}
372	              />
373	            </CenteredContainer>
374	          ) : isLoading ? (
375	            <CenteredContainer>{t('Loading...')}</CenteredContainer>
376	          ) : dataIsEmpty ? (
377	            <CenteredContainer>
378	              <Alert variant="warning" isInline isPlain title={t('No datapoints found')} />
379	            </CenteredContainer>
380	          ) : histogramData ? (
381	            <Chart
382	              height={GRAPH_HEIGHT}
383	              padding={{
384	                top: TOP_PADDING,
385	                bottom: BOTTOM_PADDING,
386	                left: LEFT_PADDING,
387	                right: 20,
388	              }}
389	              domain={{
390	                x: [timeRangeValue.start, timeRangeValue.end],
391	              }}
392	              scale={{ x: 'time', y: 'linear' }}
393	              containerComponent={
394	                <SelectVoronoiContainer
395	                  activateData={false}
396	                  labels={({ datum }: { datum: ChartData }) =>
397	                    `${datum.y !== null ? datum.y : t('No data')}`
398	                  }
399	                  labelComponent={
400	                    <HistogramTooltip
401	                      interval={intervalValue}
402	                      timezone={timezone}
403	                      legendData={legendData}
404	                    />
405	                  }
406	                  voronoiDimension="x"
407	                  voronoiPadding={0}
408	                  brushDimension="x"
409	                  onBrushDomainChangeEnd={handleTimeRangeSelection}
410	                  handleComponent={<BrushHandleComponent />}
411	                  defaultBrushArea="none"
412	                  handleWidth={1}
413	                  allowDrag={false}
414	                  brushDomain={{ x: [0, 0], y: [0, 0] }}
415	                />
416	              }
417	              width={width}
418	              domainPadding={{ x: 30, y: 10 }}
419	            >
420	              <ChartAxis
421	                tickCount={60}
422	                fixLabelOverlap
423	                tickFormat={(tick: number) =>
424	                  dateToFormat(tick, getTimeFormatFromTimeRange(timeRangeValue), timezone)
425	                }
426	              />
427	              <ChartAxis tickCount={2} dependentAxis tickFormat={valueWithScalePrefix} />
428	              <ChartStack>{groupsCharts.charts}</ChartStack>
429	            </Chart>
430	          ) : (
431	            <div>{t('No data')}</div>
432	          )}
433	        </div>
434	      </CardBody>
435	    </Card>
436	  );
437	};

