 29	
 30	const GRAPH_HEIGHT = 130;
 31	const LEFT_PADDING = 50;
 32	const BOTTOM_PADDING = 50;
 33	const TOP_PADDING = 10;
 34	
 35	const SORTED_CHART_GROUPS: Array<Severity> = [
 36	  'critical',
 37	  'error',
 38	  'warning',
 39	  'debug',
 40	  'info',
 41	  'trace',
 42	  'unknown',
 43	];
