303	    const maxBarWidth = width / 10;
304	
305	    const charts = availableGroups.map((group: Severity, index: number) => {
306	      let barData = chartsData[group];
307	
308	      /**
309	       * If we are in subsecond resolution, clamp time to current range so the bar is visible
310	       *  */
311	      if (timeRangeValue.end - timeRangeValue.start <= 1000) {
312	        barData = barData.map((d) => ({ ...d, x: clampTimeToChartRange(d.x, timeRangeValue) }));
313	      }
